"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import styles from "./page.module.css";

interface Category {
  id: number;
  name: string;
  slug: string;
}

interface Video {
  id: number;
  title: string;
  description: string | null;
  type: string;
  url: string;
  thumbnail: string | null;
  views: number;
  likes: number;
  isFeatured: boolean;
  categoryId: number | null;
  category?: Category | null;
}

interface ContactSetting {
  id: number;
  phone: string;
  email: string;
  address: string;
  whatsapp: string;
  telegram: string;
  facebook: string;
  advertisingPlans: string;
}

export default function AdminPage() {
  // Authentication states
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [authError, setAuthError] = useState("");

  // Data states
  const [videos, setVideos] = useState<Video[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [settings, setSettings] = useState<ContactSetting | null>(null);
  const [loading, setLoading] = useState(true);

  // Active navigation tab
  const [activeTab, setActiveTab] = useState<"overview" | "videos" | "categories" | "live-control">("overview");

  // Form states for Live Panel
  const [liveTitle, setLiveTitle] = useState("");
  const [liveUrl, setLiveUrl] = useState("");
  const [liveIsFeatured, setLiveIsFeatured] = useState(false);
  const [liveDescription, setLiveDescription] = useState("");

  // Sync Live form states with fetched videos array
  useEffect(() => {
    const currentLive = videos.find((v) => v.type === "LIVE");
    if (currentLive) {
      setLiveTitle(currentLive.title || "البث المباشر لقناة ليبيا بلس");
      // If it contains the embed url, we can display the embed or watch link. We show whatever is in the DB.
      setLiveUrl(currentLive.url || "");
      setLiveIsFeatured(currentLive.isFeatured);
      setLiveDescription(currentLive.description || "");
    }
  }, [videos]);

  // Modal display toggles
  const [showVideoModal, setShowVideoModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);

  // Form states
  const [videoForm, setVideoForm] = useState({
    id: "",
    title: "",
    description: "",
    type: "REEL", // "REEL", "LIVE", "YOUTUBE"
    url: "",
    thumbnail: "",
    categoryId: "",
    isFeatured: false,
  });

  const [categoryForm, setCategoryForm] = useState({
    id: "",
    name: "",
    slug: "",
  });

  const [settingsForm, setSettingsForm] = useState({
    phone: "",
    email: "",
    address: "",
    whatsapp: "",
    telegram: "",
    facebook: "",
    advertisingPlans: "",
  });

  const [statusMessage, setStatusMessage] = useState("");

  // 1. Authenticate locally on mount
  useEffect(() => {
    const authSession = localStorage.getItem("libyaplus_admin_auth");
    if (authSession === "true") {
      setIsAuthenticated(true);
    }
  }, []);

  // 2. Fetch all dashboard data if authenticated
  useEffect(() => {
    if (isAuthenticated) {
      fetchDashboardData();
    }
  }, [isAuthenticated]);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const [videosRes, catsRes, settingsRes] = await Promise.all([
        fetch("/api/videos"),
        fetch("/api/categories"),
        fetch("/api/settings"),
      ]);

      const videosData = await videosRes.json();
      const catsData = await catsRes.json();
      const settingsData = await settingsRes.json();

      setVideos(videosData);
      setCategories(catsData);
      setSettings(settingsData);

      // Pre-populate settings form
      if (settingsData) {
        setSettingsForm({
          phone: settingsData.phone || "",
          email: settingsData.email || "",
          address: settingsData.address || "",
          whatsapp: settingsData.whatsapp || "",
          telegram: settingsData.telegram || "",
          facebook: settingsData.facebook || "",
          advertisingPlans: settingsData.advertisingPlans || "",
        });
      }
    } catch (error) {
      console.error("Error loading dashboard data:", error);
    } finally {
      setLoading(false);
    }
  };

  // Lockscreen gate submission (Database Authentic Login)
  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const response = await fetch("/api/admin/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        localStorage.setItem("libyaplus_admin_auth", "true");
        setIsAuthenticated(true);
        setAuthError("");
      } else {
        setAuthError(data.error || "البريد الإلكتروني أو رمز المرور خاطئ!");
      }
    } catch (err) {
      console.error(err);
      setAuthError("حدث خطأ أثناء محاولة تسجيل الدخول.");
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("libyaplus_admin_auth");
    setIsAuthenticated(false);
    setEmail("");
    setPassword("");
  };

  const handleSaveLive = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!liveUrl.trim()) {
      alert("يرجى إدخال رابط البث المباشر من يوتيوب أولاً.");
      return;
    }

    const currentLive = videos.find((v) => v.type === "LIVE");
    const isEditing = !!currentLive;
    const urlEndpoint = "/api/videos";
    const method = isEditing ? "PUT" : "POST";

    try {
      const response = await fetch(urlEndpoint, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          id: isEditing ? currentLive.id : undefined,
          title: liveTitle,
          description: liveDescription,
          type: "LIVE",
          url: liveUrl,
          isFeatured: liveIsFeatured,
          categoryId: null,
          thumbnail: currentLive?.thumbnail || "https://images.unsplash.com/photo-1585829365295-ab7cd400c167?w=500&auto=format&fit=crop",
        }),
      });

      if (response.ok) {
        triggerStatus("تم تحديث إعدادات البث المباشر بنجاح! ✓");
        fetchDashboardData();
      } else {
        const err = await response.json();
        alert("فشل تحديث البث المباشر: " + err.error);
      }
    } catch (err) {
      console.error(err);
      alert("حدث خطأ أثناء الاتصال بالخادم لتحديث البث.");
    }
  };

  // Status flashes
  const triggerStatus = (msg: string) => {
    setStatusMessage(msg);
    setTimeout(() => setStatusMessage(""), 4000);
  };

  // ==========================================
  // VIDEOS CRUD HANDLERS
  // ==========================================
  const openAddVideo = () => {
    setVideoForm({
      id: "",
      title: "",
      description: "",
      type: "REEL",
      url: "",
      thumbnail: "",
      categoryId: "",
      isFeatured: false,
    });
    setShowVideoModal(true);
  };

  const openEditVideo = (video: Video) => {
    setVideoForm({
      id: video.id.toString(),
      title: video.title,
      description: video.description || "",
      type: video.type,
      url: video.url,
      thumbnail: video.thumbnail || "",
      categoryId: video.categoryId ? video.categoryId.toString() : "",
      isFeatured: video.isFeatured,
    });
    setShowVideoModal(true);
  };

  const handleSaveVideo = async (e: React.FormEvent) => {
    e.preventDefault();
    const isEditing = !!videoForm.id;
    const urlEndpoint = "/api/videos";
    const method = isEditing ? "PUT" : "POST";

    try {
      const response = await fetch(urlEndpoint, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...videoForm,
          id: isEditing ? parseInt(videoForm.id) : undefined,
        }),
      });

      if (response.ok) {
        triggerStatus(isEditing ? "تم تعديل الفيديو بنجاح! ✓" : "تم إضافة الفيديو بنجاح! ✓");
        setShowVideoModal(false);
        fetchDashboardData();
      } else {
        const err = await response.json();
        alert("فشل الحفظ: " + err.error);
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleDeleteVideo = async (id: number) => {
    if (!confirm("هل أنت متأكد من رغبتك في حذف هذا الفيديو نهائياً؟")) return;

    try {
      const response = await fetch(`/api/videos?id=${id}`, {
        method: "DELETE",
      });

      if (response.ok) {
        triggerStatus("تم حذف الفيديو بنجاح! ✓");
        fetchDashboardData();
      } else {
        alert("فشل حذف الفيديو.");
      }
    } catch (e) {
      console.error(e);
    }
  };

  // ==========================================
  // CATEGORIES CRUD HANDLERS
  // ==========================================
  const openAddCategory = () => {
    setCategoryForm({ id: "", name: "", slug: "" });
    setShowCategoryModal(true);
  };

  const openEditCategory = (cat: Category) => {
    setCategoryForm({
      id: cat.id.toString(),
      name: cat.name,
      slug: cat.slug,
    });
    setShowCategoryModal(true);
  };

  const handleSaveCategory = async (e: React.FormEvent) => {
    e.preventDefault();
    const isEditing = !!categoryForm.id;
    const urlEndpoint = "/api/categories";
    const method = isEditing ? "PUT" : "POST";

    try {
      const response = await fetch(urlEndpoint, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...categoryForm,
          id: isEditing ? parseInt(categoryForm.id) : undefined,
        }),
      });

      if (response.ok) {
        triggerStatus(isEditing ? "تم تعديل القسم بنجاح! ✓" : "تم إضافة القسم بنجاح! ✓");
        setShowCategoryModal(false);
        fetchDashboardData();
      } else {
        const err = await response.json();
        alert("فشل حفظ القسم: " + err.error);
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleDeleteCategory = async (id: number) => {
    if (!confirm("عند حذف هذا القسم، سيتم إلغاء تصنيف الفيديوهات التابعة له دون حذفها. هل تود المتابعة؟")) return;

    try {
      const response = await fetch(`/api/categories?id=${id}`, {
        method: "DELETE",
      });

      if (response.ok) {
        triggerStatus("تم حذف القسم بنجاح! ✓");
        fetchDashboardData();
      } else {
        alert("فشل حذف القسم.");
      }
    } catch (e) {
      console.error(e);
    }
  };

  // ==========================================
  // SETTINGS HANDLER
  // ==========================================
  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();

    // Verify plans JSON is valid
    try {
      if (settingsForm.advertisingPlans) {
        JSON.parse(settingsForm.advertisingPlans);
      }
    } catch (err) {
      alert("خطأ: بنية خطط الأسعار الإعلانية ليست كائن JSON صالح! يرجى تصحيح الأقواس والمحتوى.");
      return;
    }

    try {
      const response = await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(settingsForm),
      });

      if (response.ok) {
        triggerStatus("تم حفظ إعدادات التواصل وخطط الإعلانات بنجاح! ✓");
        fetchDashboardData();
      } else {
        alert("فشل حفظ الإعدادات.");
      }
    } catch (e) {
      console.error(e);
    }
  };

  // Lockscreen component (Authentication Gate)
  if (!isAuthenticated) {
    return (
      <div className={styles.lockScreenContainer}>
        <div className={`${styles.lockCard} glass-card`}>
          <div className={styles.shieldIcon}>
            <img src="/logl.png" alt="ليبيا بلس" style={{ height: "65px", marginBottom: "15px", objectFit: "contain" }} />
          </div>
          <h2 style={{ fontSize: "1.4rem" }}>بوابة المشرفين الآمنة</h2>
          <p style={{ color: "var(--text-secondary)", fontSize: "0.85rem" }}>
            سجل دخولك بالبريد الإلكتروني وكلمة المرور لإدارة منصة ليبيا بلس الرقمية.
          </p>
          <form onSubmit={handleLogin} style={{ width: "100%", display: "flex", flexDirection: "column", gap: "14px" }}>
            <div className="form-group" style={{ margin: 0, textAlign: "right" }}>
              <label className="form-label">البريد الإلكتروني *</label>
              <input
                type="email"
                className="form-control"
                placeholder="motaz@gmail.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>
            <div className="form-group" style={{ margin: 0, textAlign: "right" }}>
              <label className="form-label">كلمة المرور *</label>
              <input
                type="password"
                className="form-control"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>
            {authError && <p style={{ color: "#ef4444", fontSize: "0.825rem", textAlign: "center", margin: 0 }}>{authError}</p>}
            <button type="submit" className="btn btn-primary" style={{ width: "100%", marginTop: "8px" }}>
              🔑 تسجيل الدخول الآمن
            </button>
          </form>
        </div>
      </div>
    );
  }

  // Dashboard Core UI
  return (
    <div className={styles.dashboardShell}>
      
      {/* 1. Header Admin Bar */}
      <header className={styles.topBar}>
        <div className={styles.brandText} style={{ display: "flex", alignItems: "center" }}>
          <img src="/logl.png" alt="ليبيا بلس" style={{ height: "38px", objectFit: "contain", verticalAlign: "middle", marginLeft: "12px" }} />
          <span style={{ fontSize: "1.05rem", fontWeight: "750", color: "var(--text-primary)" }}>لوحة التحكم</span>
        </div>
        <div style={{ display: "flex", gap: "12px" }}>
          <Link href="/" className="btn btn-secondary" style={{ fontSize: "0.85rem", padding: "8px 16px" }}>
            📺 منصة العرض
          </Link>
          <button onClick={handleLogout} className="btn btn-danger" style={{ fontSize: "0.85rem", padding: "8px 16px" }}>
            🔒 تسجيل الخروج
          </button>
        </div>
      </header>

      {/* Status Flasher HUD */}
      {statusMessage && (
        <div style={{ position: "fixed", top: "85px", left: "20px", background: "rgba(16,185,129,0.9)", backdropFilter: "blur(4px)", color: "#fff", padding: "12px 24px", borderRadius: "10px", zIndex: 2000, fontWeight: "600", fontSize: "0.9rem", boxShadow: "0 4px 15px rgba(0,0,0,0.3)" }}>
          {statusMessage}
        </div>
      )}

      {/* 2. Main Grid Layout */}
      <div className={styles.mainGrid}>
        
        {/* Sidebar Nav */}
        <aside className={styles.sidebar}>
          <button
            onClick={() => setActiveTab("overview")}
            className={`${styles.tabBtn} ${activeTab === "overview" ? styles.activeTabBtn : ""}`}
          >
            📊 نظرة عامة
          </button>
          <button
            onClick={() => setActiveTab("live-control")}
            className={`${styles.tabBtn} ${activeTab === "live-control" ? styles.activeTabBtn : ""}`}
          >
            🔴 البث المباشر (لايف)
          </button>
          <button
            onClick={() => setActiveTab("videos")}
            className={`${styles.tabBtn} ${activeTab === "videos" ? styles.activeTabBtn : ""}`}
          >
            🎥 الفيديوهات والريلز
          </button>
          <button
            onClick={() => setActiveTab("categories")}
            className={`${styles.tabBtn} ${activeTab === "categories" ? styles.activeTabBtn : ""}`}
          >
            📁 تصنيفات الأقسام
          </button>
        </aside>

        {/* Content Display Panels */}
        <main className={styles.contentArea}>
          {loading ? (
            <div style={{ display: "flex", justifyContent: "center", alignItems: "center", height: "200px" }}>
              <span style={{ fontSize: "1.2rem", color: "var(--text-secondary)" }}>جاري تحميل البيانات...</span>
            </div>
          ) : (
            <>
              {/* TAB 1: OVERVIEW STATISTICS */}
              {activeTab === "overview" && (
                <div className="fade-in">
                  <div className={styles.statsRow}>
                    <div className={`${styles.statCard} glass-card`}>
                      <div className={styles.statDetails}>
                        <div className={styles.statNum}>{videos.filter((v) => v.type === "REEL").length}</div>
                        <div className={styles.statLabel}>فيديوهات ريلز</div>
                      </div>
                      <span className={styles.statIcon}>📱</span>
                    </div>

                    <div className={`${styles.statCard} glass-card`}>
                      <div className={styles.statDetails}>
                        <div className={styles.statNum}>{videos.filter((v) => v.type === "YOUTUBE").length}</div>
                        <div className={styles.statLabel}>تقارير يوتيوب</div>
                      </div>
                      <span className={styles.statIcon}>🎥</span>
                    </div>

                    <div className={`${styles.statCard} glass-card`}>
                      <div className={styles.statDetails}>
                        <div className={styles.statNum}>{categories.length}</div>
                        <div className={styles.statLabel}>أقسام مصنفة</div>
                      </div>
                      <span className={styles.statIcon}>📁</span>
                    </div>

                    <div className={`${styles.statCard} glass-card`}>
                      <div className={styles.statDetails}>
                        <div className={styles.statNum}>
                          {videos.filter((v) => v.type === "LIVE" && v.isFeatured).length > 0 ? "نشط" : "مغلق"}
                        </div>
                        <div className={styles.statLabel}>حالة البث المباشر</div>
                      </div>
                      <span className={styles.statIcon}>🔴</span>
                    </div>
                  </div>

                  <h3 style={{ marginBottom: "16px" }}>آخر المحتويات المضافة</h3>
                  <div className={styles.tableWrapper}>
                    <table className={styles.dataTable}>
                      <thead>
                        <tr>
                          <th>الملصق</th>
                          <th>العنوان</th>
                          <th>النوع</th>
                          <th>المشاهدات</th>
                          <th>القسم</th>
                        </tr>
                      </thead>
                      <tbody>
                        {videos.slice(0, 5).map((video) => (
                          <tr key={video.id}>
                            <td>
                              <img src={video.thumbnail || "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=100"} className={styles.avatar} alt="" />
                            </td>
                            <td>{video.title}</td>
                            <td>
                              <span className={`${styles.rowBadge} ${video.type === "REEL" ? styles.badgeReel : video.type === "LIVE" ? styles.badgeLive : styles.badgeYoutube}`}>
                                {video.type === "REEL" ? "ريلز" : video.type === "LIVE" ? "لايف مباشر" : "يوتيوب"}
                              </span>
                            </td>
                            <td>{video.views.toLocaleString()}</td>
                            <td>{video.category ? video.category.name : "غير مصنف"}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* TAB: LIVE STREAM CONTROL CENTER */}
              {activeTab === "live-control" && (
                <div className="fade-in">
                  <div className={styles.panelHeader}>
                    <h2>غرفة التحكم بالبث المباشر (لايف) 🔴</h2>
                  </div>

                  <div className="glass-card" style={{ padding: "35px", display: "flex", flexDirection: "column", gap: "24px", maxWidth: "800px", margin: "0 auto" }}>
                    
                    {/* Live Broadcast Status Banner */}
                    <div style={{
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "space-between",
                      padding: "20px",
                      borderRadius: "14px",
                      background: liveIsFeatured ? "rgba(220, 38, 38, 0.08)" : "rgba(100, 116, 139, 0.08)",
                      border: liveIsFeatured ? "1px solid rgba(220, 38, 38, 0.2)" : "1px solid rgba(100, 116, 139, 0.2)",
                      transition: "all 0.3s ease"
                    }}>
                      <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
                        <span style={{
                          fontSize: "2rem",
                          display: "inline-block"
                        }}>
                          {liveIsFeatured ? "🔴" : "⚫"}
                        </span>
                        <div>
                          <h4 style={{ margin: 0, fontSize: "1.1rem", color: "var(--text-primary)" }}>
                            {liveIsFeatured ? "البث المباشر نشط الآن" : "البث المباشر متوقف حالياً"}
                          </h4>
                          <p style={{ margin: "4px 0 0 0", fontSize: "0.85rem", color: "var(--text-secondary)" }}>
                            {liveIsFeatured ? "يظهر البث المباشر للزوار في شريط البانر بالصفحة الرئيسية وصفحة البث المخصص." : "يظهر للزوار لوحة الانتظار والترقب بالبث التجريبي."}
                          </p>
                        </div>
                      </div>
                      <div style={{ display: "flex", gap: "10px" }}>
                        <button
                          type="button"
                          onClick={() => setLiveIsFeatured(true)}
                          className={`btn ${liveIsFeatured ? "btn-primary" : "btn-secondary"}`}
                          style={{ fontSize: "0.85rem", padding: "8px 16px" }}
                        >
                          ▶ تشغيل البث
                        </button>
                        <button
                          type="button"
                          onClick={() => setLiveIsFeatured(false)}
                          className={`btn ${!liveIsFeatured ? "btn-danger" : "btn-secondary"}`}
                          style={{ fontSize: "0.85rem", padding: "8px 16px" }}
                        >
                          ⏸ إيقاف البث
                        </button>
                      </div>
                    </div>

                    {/* Live URL Form */}
                    <form onSubmit={handleSaveLive} style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
                      
                      <div className="form-group">
                        <label className="form-label" style={{ fontWeight: "750" }}>
                          رابط فيديو البث المباشر من يوتيوب *
                        </label>
                        <input
                          type="url"
                          className="form-control"
                          required
                          value={liveUrl}
                          onChange={(e) => setLiveUrl(e.target.value)}
                          placeholder="مثال: https://www.youtube.com/watch?v=... أو رابط مشاركة البث"
                          style={{ width: "100%", fontSize: "0.95rem" }}
                        />
                        <span style={{ fontSize: "0.8rem", color: "var(--text-secondary)", marginTop: "6px", display: "block" }}>
                          💡 يمكنك نسخ ولصق رابط يوتيوب المباشر كاملاً وسيقوم النظام تلقائياً باستخلاص البث وتجهيز شاشة العرض للمشاهدين.
                        </span>
                      </div>

                      <div className="form-group">
                        <label className="form-label" style={{ fontWeight: "750" }}>
                          عنوان التغطية أو البث
                        </label>
                        <input
                          type="text"
                          className="form-control"
                          value={liveTitle}
                          onChange={(e) => setLiveTitle(e.target.value)}
                          placeholder="مثال: البث المباشر لقناة ليبيا بلس - تغطية شاملة"
                          style={{ width: "100%" }}
                        />
                      </div>

                      <div className="form-group">
                        <label className="form-label" style={{ fontWeight: "750" }}>
                          وصف البث والتغطية
                        </label>
                        <textarea
                          className="form-control"
                          rows={4}
                          value={liveDescription}
                          onChange={(e) => setLiveDescription(e.target.value)}
                          placeholder="اكتب هنا تفاصيل البث المباشر الحالي لتعريف الزوار..."
                          style={{ width: "100%" }}
                        />
                      </div>

                      <div style={{ marginTop: "10px", display: "flex", justifyContent: "flex-end" }}>
                        <button type="submit" className="btn btn-primary" style={{ padding: "12px 30px", fontSize: "0.95rem" }}>
                          💾 حفظ وتطبيق إعدادات البث المباشر
                        </button>
                      </div>

                    </form>

                  </div>
                </div>
              )}

              {/* TAB 2: VIDEOS & REELS CRUD */}
              {activeTab === "videos" && (
                <div className="fade-in">
                  <div className={styles.panelHeader}>
                    <h2>إدارة الفيديوهات والمقاطع</h2>
                    <button onClick={openAddVideo} className="btn btn-primary">
                      ➕ إضافة فيديو جديد
                    </button>
                  </div>

                  <div className={styles.tableWrapper}>
                    <table className={styles.dataTable}>
                      <thead>
                        <tr>
                          <th>الملصق</th>
                          <th>العنوان</th>
                          <th>النوع</th>
                          <th>القسم</th>
                          <th>الرعاية البارزة</th>
                          <th>المشاهدات</th>
                          <th>الإعجابات</th>
                          <th>الخيارات</th>
                        </tr>
                      </thead>
                      <tbody>
                        {videos.map((video) => (
                          <tr key={video.id}>
                            <td>
                              <img src={video.thumbnail || "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=100"} className={styles.avatar} alt="" />
                            </td>
                            <td style={{ maxWidth: "250px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                              {video.title}
                            </td>
                            <td>
                              <span className={`${styles.rowBadge} ${video.type === "REEL" ? styles.badgeReel : video.type === "LIVE" ? styles.badgeLive : styles.badgeYoutube}`}>
                                {video.type === "REEL" ? "ريلز" : video.type === "LIVE" ? "لايف مباشر" : "يوتيوب"}
                              </span>
                            </td>
                            <td>{video.category ? video.category.name : "غير مصنف"}</td>
                            <td>{video.isFeatured ? "⭐ نعم مميز" : "لا"}</td>
                            <td>{video.views.toLocaleString()}</td>
                            <td>{video.likes.toLocaleString()}</td>
                            <td>
                              <div style={{ display: "flex", gap: "8px" }}>
                                <button onClick={() => openEditVideo(video)} className="btn btn-secondary" style={{ padding: "6px 12px", fontSize: "0.8rem" }}>
                                  ✏️ تعديل
                                </button>
                                <button onClick={() => handleDeleteVideo(video.id)} className="btn btn-danger" style={{ padding: "6px 12px", fontSize: "0.8rem" }}>
                                  🗑️ حذف
                                </button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* TAB 3: CATEGORIES CRUD */}
              {activeTab === "categories" && (
                <div className="fade-in">
                  <div className={styles.panelHeader}>
                    <h2>إدارة تصنيفات الأقسام</h2>
                    <button onClick={openAddCategory} className="btn btn-primary">
                      ➕ إضافة قسم جديد
                    </button>
                  </div>

                  <div className={styles.tableWrapper}>
                    <table className={styles.dataTable}>
                      <thead>
                        <tr>
                          <th>الرقم</th>
                          <th>اسم القسم</th>
                          <th>الوسم الرابط (Slug)</th>
                          <th>الفيديوهات الملحقة</th>
                          <th>الخيارات</th>
                        </tr>
                      </thead>
                      <tbody>
                        {categories.map((cat) => (
                          <tr key={cat.id}>
                            <td>{cat.id}</td>
                            <td>{cat.name}</td>
                            <td className="ltr">{cat.slug}</td>
                            <td>
                              {videos.filter((v) => v.categoryId === cat.id).length} فيديو
                            </td>
                            <td>
                              <div style={{ display: "flex", gap: "8px" }}>
                                <button onClick={() => openEditCategory(cat)} className="btn btn-secondary" style={{ padding: "6px 12px", fontSize: "0.8rem" }}>
                                  ✏️ تعديل
                                </button>
                                <button onClick={() => handleDeleteCategory(cat.id)} className="btn btn-danger" style={{ padding: "6px 12px", fontSize: "0.8rem" }}>
                                  🗑️ حذف
                                </button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}


            </>
          )}
        </main>
      </div>

      {/* ==========================================
          MODAL: VIDEO ADD/EDIT
          ========================================== */}
      {showVideoModal && (
        <div className={styles.modalOverlay}>
          <div className={styles.modalContent}>
            <div className={styles.modalHeader}>
              <h3>{videoForm.id ? "تعديل بيانات الفيديو" : "إضافة فيديو جديد للمنصة"}</h3>
              <button onClick={() => setShowVideoModal(false)} style={{ background: "transparent", border: "none", fontSize: "1.5rem", color: "var(--text-muted)", cursor: "pointer" }}>
                ✕
              </button>
            </div>
            
            <form onSubmit={handleSaveVideo} style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
              <div className="form-group">
                <label className="form-label">نوع الفيديو *</label>
                <select
                  className="form-control"
                  value={videoForm.type}
                  onChange={(e) => setVideoForm({ ...videoForm, type: e.target.value })}
                  required
                >
                  <option value="REEL">📱 مقطع ريلز قصير (عمودي)</option>
                  <option value="LIVE">🔴 قناة البث المباشر (يوتيوب لايف)</option>
                  <option value="YOUTUBE">🎥 منشور فيديو يوتيوب عادي</option>
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">عنوان الفيديو *</label>
                <input
                  type="text"
                  className="form-control"
                  required
                  value={videoForm.title}
                  onChange={(e) => setVideoForm({ ...videoForm, title: e.target.value })}
                  placeholder="اكتب عنواناً جذاباً..."
                />
              </div>

              <div className="form-group">
                <label className="form-label">الوصف / التفاصيل</label>
                <textarea
                  className="form-control"
                  rows={3}
                  value={videoForm.description}
                  onChange={(e) => setVideoForm({ ...videoForm, description: e.target.value })}
                  placeholder="وصف تفصيلي يظهر للمشاهدين..."
                />
              </div>

              <div className="form-group">
                <label className="form-label">رابط الفيديو (URL) *</label>
                <input
                  type="url"
                  className="form-control"
                  required
                  value={videoForm.url}
                  onChange={(e) => setVideoForm({ ...videoForm, url: e.target.value })}
                  placeholder={videoForm.type === "REEL" ? "رابط MP4 المباشر (مثل: https://assets...mp4)" : "رابط فيديو يوتيوب (مثل: https://www.youtube.com/watch?v=...)"}
                />
              </div>

              {videoForm.type === "REEL" && (
                <div className="form-group">
                  <label className="form-label">رابط غلاف الفيديو / الصورة المصغرة (اختياري للريلز)</label>
                  <input
                    type="url"
                    className="form-control"
                    value={videoForm.thumbnail}
                    onChange={(e) => setVideoForm({ ...videoForm, thumbnail: e.target.value })}
                    placeholder="رابط غلاف الصورة..."
                  />
                </div>
              )}

              {videoForm.type !== "LIVE" && (
                <div className="form-group">
                  <label className="form-label">القسم الملحق</label>
                  <select
                    className="form-control"
                    value={videoForm.categoryId}
                    onChange={(e) => setVideoForm({ ...videoForm, categoryId: e.target.value })}
                  >
                    <option value="">-- بدون قسم / غير مصنف --</option>
                    {categories.map((cat) => (
                      <option key={cat.id} value={cat.id.toString()}>
                        {cat.name}
                      </option>
                    ))}
                  </select>
                </div>
              )}

              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginTop: "10px" }}>
                <input
                  type="checkbox"
                  id="isFeaturedCheck"
                  checked={videoForm.isFeatured}
                  onChange={(e) => setVideoForm({ ...videoForm, isFeatured: e.target.checked })}
                  style={{ width: "18px", height: "18px", accentColor: "var(--primary)" }}
                />
                <label htmlFor="isFeaturedCheck" className="form-label" style={{ marginBottom: 0, cursor: "pointer" }}>
                  ⭐ تحديد كبث/فيديو مميز في الصفحة الرئيسية
                </label>
              </div>

              <div className={styles.modalActions}>
                <button type="button" onClick={() => setShowVideoModal(false)} className="btn btn-secondary">
                  إلغاء
                </button>
                <button type="submit" className="btn btn-primary">
                  💾 حفظ التغييرات
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ==========================================
          MODAL: CATEGORY ADD/EDIT
          ========================================== */}
      {showCategoryModal && (
        <div className={styles.modalOverlay}>
          <div className={styles.modalContent} style={{ maxWidth: "450px" }}>
            <div className={styles.modalHeader}>
              <h3>{categoryForm.id ? "تعديل بيانات القسم" : "إضافة قسم تصنيف جديد"}</h3>
              <button onClick={() => setShowCategoryModal(false)} style={{ background: "transparent", border: "none", fontSize: "1.5rem", color: "var(--text-muted)", cursor: "pointer" }}>
                ✕
              </button>
            </div>
            
            <form onSubmit={handleSaveCategory} style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
              <div className="form-group">
                <label className="form-label">اسم القسم (بالعربية) *</label>
                <input
                  type="text"
                  className="form-control"
                  required
                  value={categoryForm.name}
                  onChange={(e) => setCategoryForm({ ...categoryForm, name: e.target.value })}
                  placeholder="مثال: منوعات، رياضة..."
                />
              </div>

              <div className="form-group">
                <label className="form-label">اسم الوسم المعرف الفريد (Slug - اختياري)</label>
                <input
                  type="text"
                  className="form-control"
                  value={categoryForm.slug}
                  onChange={(e) => setCategoryForm({ ...categoryForm, slug: e.target.value })}
                  placeholder="مثال: sports (سيتم إنشاؤه تلقائياً إن ترك فارغاً)"
                  style={{ direction: "ltr", textAlign: "left" }}
                />
              </div>

              <div className={styles.modalActions}>
                <button type="button" onClick={() => setShowCategoryModal(false)} className="btn btn-secondary">
                  إلغاء
                </button>
                <button type="submit" className="btn btn-primary">
                  💾 حفظ التغييرات
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

    </div>
  );
}
